"use client";

import { useEffect, useRef, useState } from "react";
import maplibregl, { Map as MLMap, ScaleControl } from "maplibre-gl";
import "maplibre-gl/dist/maplibre-gl.css";
import { BASEMAPS, DEFAULT_BASEMAP_ID, type Basemap } from "@/lib/basemaps";

interface ViewState {
  center: [number, number];
  zoom: number;
}

function rasterStyle(basemap: Basemap) {
  return {
    version: 8 as const,
    sources: {
      base: {
        type: "raster" as const,
        tiles: [basemap.url],
        tileSize: basemap.tileSize ?? 256,
        attribution: basemap.attribution,
        maxzoom: basemap.maxzoom ?? 18,
      },
    },
    layers: [{ id: "base", type: "raster" as const, source: "base" }],
  };
}

async function applyBasemap(map: MLMap, basemap: Basemap) {
  if (basemap.kind === "raster") {
    map.setStyle(rasterStyle(basemap));
    return;
  }
  map.setStyle(basemap.url);
}

export function LiveMap() {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<MLMap | null>(null);
  const [active, setActive] = useState<string>(DEFAULT_BASEMAP_ID);
  const [view, setView] = useState<ViewState>({
    center: [6.775, 51.2277],
    zoom: 12,
  });

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const initial = BASEMAPS.find((b) => b.id === DEFAULT_BASEMAP_ID) ?? BASEMAPS[0];

    const map = new maplibregl.Map({
      container: containerRef.current,
      style: initial.kind === "raster" ? rasterStyle(initial) : initial.url,
      center: view.center,
      zoom: view.zoom,
      minZoom: 2,
      maxZoom: 18,
      attributionControl: { compact: true },
      hash: true,
    });
    mapRef.current = map;

    map.addControl(new maplibregl.NavigationControl({ showCompass: true }), "top-right");
    map.addControl(new ScaleControl({ maxWidth: 120, unit: "metric" }), "bottom-left");
    map.addControl(new maplibregl.FullscreenControl(), "top-right");
    map.addControl(new maplibregl.GeolocateControl({ trackUserLocation: false }), "top-right");

    map.on("moveend", () => {
      const c = map.getCenter();
      setView({ center: [c.lng, c.lat], zoom: map.getZoom() });
    });

    const resizeObserver = new ResizeObserver(() => {
      map.resize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      map.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;
    const basemap = BASEMAPS.find((b) => b.id === active);
    if (!basemap) return;
    applyBasemap(map, basemap);
  }, [active]);

  const activeBm = BASEMAPS.find((b) => b.id === active);

  return (
    <div className="relative h-full w-full">
      <div ref={containerRef} className="h-full w-full" />

      <div className="pointer-events-none absolute left-3 top-3 z-10 flex flex-col gap-2">
        <div className="pointer-events-auto rounded-xl border border-neutral-700 bg-neutral-900/85 p-2 text-xs text-neutral-200 shadow-xl backdrop-blur">
          <div className="mb-1.5 px-1 text-[10px] font-semibold uppercase tracking-wider text-neutral-500">
            Basemap
          </div>
          <div className="flex flex-col gap-1">
            {BASEMAPS.map((b) => (
              <button
                key={b.id}
                type="button"
                onClick={() => setActive(b.id)}
                className={`rounded-lg px-2.5 py-1.5 text-left transition-colors ${
                  active === b.id
                    ? "bg-sky-500/20 text-sky-200 ring-1 ring-inset ring-sky-500/50"
                    : "text-neutral-300 hover:bg-neutral-800"
                }`}
              >
                {b.label}
              </button>
            ))}
          </div>
        </div>

        <div className="pointer-events-auto rounded-lg border border-neutral-700 bg-neutral-900/85 px-3 py-1.5 font-mono text-[11px] text-neutral-400 shadow backdrop-blur">
          {view.center[1].toFixed(4)}°, {view.center[0].toFixed(4)}° · z{view.zoom.toFixed(1)}
          {activeBm?.maxzoom != null && view.zoom > activeBm.maxzoom && (
            <span className="ml-2 text-amber-400">(upsampled)</span>
          )}
        </div>
      </div>
    </div>
  );
}
